('spanish:8-2-social-media-and-online-safety:misc:b6ae401e', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Es importante que tienes cuidado.</p><p><strong>✅ The correct idea:</strong> Es importante que tengas cuidado.</p>", "question": "Why must ‘tienes’ change to ‘tengas’ here?", "options": ["‘es importante que’ triggers the subjunctive mood", "‘tienes’ is spelt incorrectly and should have an accent", "the sentence needs the imperfect tense instead", "‘que’ should be removed from the sentence"]}'::jsonb, '{"answer": 0, "explain": "es importante que is a subjunctive trigger, so tienes → tengas."}'::jsonb),
('spanish:8-2-social-media-and-online-safety:tips:86ec8146', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 1 — Dictation (listening)", "reading": "Safety-advice sentences reuse chunks you know: ‘no se debe…’, ‘hay que…’, ‘es importante…’. Listen carefully for the negative ‘no’ before ‘se debe’ — missing it reverses the whole meaning of the advice.", "question": "You hear ‘…no se debe…’ but write ‘se debe’. What has gone wrong?", "options": ["the advice has been reversed by missing the negative ‘no’", "nothing at all — ‘se debe’ and ‘no se debe’ mean exactly the same thing", "the tense has changed from present to past", "the subject of the sentence has changed"]}'::jsonb, '{"answer": 0, "explain": "Missing ‘no’ turns ‘you must not’ into ‘you must’ — the opposite meaning."}'::jsonb),
('spanish:8-2-social-media-and-online-safety:tips:71e72cea', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'tips', 'mcq', 1, '{"readingTitle": "tip — Paper 3 — Reading and translation into English", "reading": "Watch the false friend ‘red’ (network, not colour) and keep translations natural: ‘compartir datos personales’ = ‘to share personal data’, not a word-for-word oddity. Look out for ‘ciberacoso’, a topic-specific word worth learning by sight.", "question": "‘Nunca comparto mis datos personales en línea’ means…", "options": ["I never share my personal data online", "I always share my personal data online", "I sometimes share photos online", "I never go online at all"]}'::jsonb, '{"answer": 0, "explain": "nunca = never; comparto = I share; the sentence is a negative statement about sharing data."}'::jsonb),
('spanish:8-2-social-media-and-online-safety:tips:2f1a4fab', 'spanish', 'spanish:8-2-social-media-and-online-safety', '8.2 Social Media and Online Safety', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Paper 4 — Writing & translation into Spanish", "reading": "Combine an opinion, advice and a reason: ‘Uso las redes sociales porque es divertido, pero es importante proteger tu contraseña.’ At Higher, add the subjunctive and conditional: ‘es importante que tengas cuidado’, ‘se debería tener más cuidado’.", "question": "Which answer reaches the top band?", "options": ["Uso las redes sociales porque es divertido, pero es importante que tengas cuidado", "Uso las redes sociales y es divertido y divertido y muy divertido y divertido siempre", "Las redes sociales son buenas", "Tengo un perfil"]}'::jsonb, '{"answer": 0, "explain": "It links an opinion, a reason and a Higher-tier subjunctive structure — range and accuracy, not just length."}'::jsonb),
